import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"北京动物园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/beijing-zoo.md","filePath":"parks/beijing-zoo.md","lastUpdated":1784773307000}'),d={name:"parks/beijing-zoo.md"};function n(s,t,i,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="北京动物园" tabindex="-1">北京动物园 <a class="header-anchor" href="#北京动物园" aria-label="Permalink to &quot;北京动物园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-AfRCvaeieVk?w=1200" alt="北京动物园"></p><blockquote><p>&quot;动物王国，童趣天地。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>北京动物园位于北京市西城区，是中国最大的动物园之一，也是世界上最著名的动物园之一。动物园占地面积约90公顷，饲养着各种珍稀动物约500种，数量超过1万只。北京动物园不仅是一个观赏动物的场所，也是进行动物保护和科学研究的重要基地。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">7:30-18:00（旺季），7:30-17:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">15元（旺季），10元（淡季）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜，春夏最佳</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁4号线动物园站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区西直门外大街137号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="清末始建" tabindex="-1">清末始建 <a class="header-anchor" href="#清末始建" aria-label="Permalink to &quot;清末始建&quot;">​</a></h3><p>北京动物园的前身是清末的&quot;万牲园&quot;，建于1908年，是中国最早的动物园。</p><h4 id="发展历程" tabindex="-1">发展历程 <a class="header-anchor" href="#发展历程" aria-label="Permalink to &quot;发展历程&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">事件</th></tr></thead><tbody><tr><td style="text-align:left;">1908年</td><td style="text-align:left;">万牲园建立</td></tr><tr><td style="text-align:left;">1928年</td><td style="text-align:left;">改名为&quot;北平动物园&quot;</td></tr><tr><td style="text-align:left;">1949年</td><td style="text-align:left;">新中国成立后，改名为&quot;北京动物园&quot;</td></tr><tr><td style="text-align:left;">1955年</td><td style="text-align:left;">北京动物园正式对外开放</td></tr><tr><td style="text-align:left;">1990年代</td><td style="text-align:left;">动物园进行了大规模的改造升级</td></tr><tr><td style="text-align:left;">2008年</td><td style="text-align:left;">北京动物园进行了数字化升级</td></tr></tbody></table><h2 id="主要景点" tabindex="-1">主要景点 <a class="header-anchor" href="#主要景点" aria-label="Permalink to &quot;主要景点&quot;">​</a></h2><h3 id="大熊猫馆" tabindex="-1">大熊猫馆 <a class="header-anchor" href="#大熊猫馆" aria-label="Permalink to &quot;大熊猫馆&quot;">​</a></h3><p>大熊猫馆是北京动物园最受欢迎的场馆之一，展示了中国国宝大熊猫。</p><h4 id="大熊猫" tabindex="-1">大熊猫 <a class="header-anchor" href="#大熊猫" aria-label="Permalink to &quot;大熊猫&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>数量</strong></td><td style="text-align:left;">多只</td></tr><tr><td style="text-align:left;"><strong>年龄</strong></td><td style="text-align:left;">不同年龄段</td></tr><tr><td style="text-align:left;"><strong>活动</strong></td><td style="text-align:left;">进食、玩耍、睡觉</td></tr><tr><td style="text-align:left;"><strong>最佳观赏时间</strong></td><td style="text-align:left;">上午9:00-11:00，下午2:00-4:00</td></tr></tbody></table><h3 id="海洋馆" tabindex="-1">海洋馆 <a class="header-anchor" href="#海洋馆" aria-label="Permalink to &quot;海洋馆&quot;">​</a></h3><p>北京动物园海洋馆是中国最大的海洋馆之一，展示了各种海洋生物。</p><h4 id="海洋生物" tabindex="-1">海洋生物 <a class="header-anchor" href="#海洋生物" aria-label="Permalink to &quot;海洋生物&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">生物</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>海豚</strong></td><td style="text-align:left;">海豚表演</td></tr><tr><td style="text-align:left;"><strong>海狮</strong></td><td style="text-align:left;">海狮表演</td></tr><tr><td style="text-align:left;"><strong>鲨鱼</strong></td><td style="text-align:left;">鲨鱼馆</td></tr><tr><td style="text-align:left;"><strong>企鹅</strong></td><td style="text-align:left;">企鹅馆</td></tr><tr><td style="text-align:left;"><strong>水母</strong></td><td style="text-align:left;">水母馆</td></tr></tbody></table><h3 id="其他动物馆" tabindex="-1">其他动物馆 <a class="header-anchor" href="#其他动物馆" aria-label="Permalink to &quot;其他动物馆&quot;">​</a></h3><p>北京动物园设有多个动物馆，展示了各种珍稀动物。</p><h4 id="主要动物馆" tabindex="-1">主要动物馆 <a class="header-anchor" href="#主要动物馆" aria-label="Permalink to &quot;主要动物馆&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">动物馆</th><th style="text-align:left;">特色</th><th style="text-align:left;">代表动物</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>狮虎山</strong></td><td style="text-align:left;">大型猫科动物</td><td style="text-align:left;">狮子、老虎</td></tr><tr><td style="text-align:left;"><strong>猴山</strong></td><td style="text-align:left;">灵长类动物</td><td style="text-align:left;">各种猴子</td></tr><tr><td style="text-align:left;"><strong>长颈鹿馆</strong></td><td style="text-align:left;">长颈鹿</td><td style="text-align:left;">长颈鹿</td></tr><tr><td style="text-align:left;"><strong>大象馆</strong></td><td style="text-align:left;">大象</td><td style="text-align:left;">亚洲象、非洲象</td></tr><tr><td style="text-align:left;"><strong>河马馆</strong></td><td style="text-align:left;">河马</td><td style="text-align:left;">河马</td></tr><tr><td style="text-align:left;"><strong>犀牛馆</strong></td><td style="text-align:left;">犀牛</td><td style="text-align:left;">白犀牛、黑犀牛</td></tr><tr><td style="text-align:left;"><strong>熊山</strong></td><td style="text-align:left;">熊</td><td style="text-align:left;">棕熊、黑熊、北极熊</td></tr><tr><td style="text-align:left;"><strong>狼山</strong></td><td style="text-align:left;">狼</td><td style="text-align:left;">狼</td></tr><tr><td style="text-align:left;"><strong>鹿苑</strong></td><td style="text-align:left;">鹿</td><td style="text-align:left;">各种鹿</td></tr><tr><td style="text-align:left;"><strong>鸟苑</strong></td><td style="text-align:left;">鸟类</td><td style="text-align:left;">各种鸟类</td></tr></tbody></table><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约4小时）</strong>：</p><p>入口 → 大熊猫馆 → 海洋馆 → 狮虎山 → 猴山 → 长颈鹿馆 → 大象馆 → 河马馆 → 出口</p><p><strong>亲子路线（约半天）</strong>：</p><p>入口 → 大熊猫馆 → 海洋馆 → 猴山 → 长颈鹿馆 → 鹿苑 → 鸟苑 → 出口</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>最佳时间</strong>：上午动物比较活跃，建议早去</li><li><strong>海洋馆</strong>：建议提前了解表演时间</li><li><strong>拍照位置</strong>：大熊猫馆、海洋馆都是绝佳拍照点</li><li><strong>餐饮推荐</strong>：园内有餐厅，也可以自带食物</li><li><strong>交通建议</strong>：地铁4号线直达，非常方便</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">4号线动物园站A口</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">7、15、19、27、45、102、103、105、107、111、305、332、334、347、360、362、534、563、604、632、685、特4、特5路动物园站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;北京动物园&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">北京海洋馆</td><td style="text-align:center;">园内</td><td style="text-align:left;">海洋生物</td></tr><tr><td style="text-align:left;">北京展览馆</td><td style="text-align:center;">约1公里</td><td style="text-align:left;">展览馆</td></tr><tr><td style="text-align:left;">动物园服装批发市场</td><td style="text-align:center;">约1公里</td><td style="text-align:left;">服装批发</td></tr><tr><td style="text-align:left;">紫竹院公园</td><td style="text-align:center;">约2公里</td><td style="text-align:left;">城市公园</td></tr></tbody></table><hr><p>** 地址**：北京市西城区西直门外大街137号 ** 地铁**：4号线动物园站A口 <strong>📞 电话</strong>：010-68314411 <strong>🌐 官网</strong>：<a href="http://www.beijingzoo.com.cn" target="_blank" rel="noreferrer">www.beijingzoo.com.cn</a></p><p><strong>💡 Tips</strong>：北京动物园的大熊猫馆人气非常旺，建议早去排队。海洋馆的表演时间可以提前在官网查询。</p>',40)])])}const y=e(d,[["render",n]]);export{f as __pageData,y as default};
